# Category: oidc_nonce_validation

import os
import json
import secrets
from functools import wraps

import requests
from flask import Flask, redirect, url_for, session, request, jsonify, render_template_string
from jose import jwt, JWTError
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OIDC Configuration - set these via environment variables
OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://accounts.google.com'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': os.environ.get('OIDC_SCOPE', 'openid email profile'),
}

# Cache for OIDC discovery document and JWKS
_oidc_discovery = None
_jwks = None


def get_oidc_discovery():
    """Fetch and cache the OIDC discovery document from the provider."""
    global _oidc_discovery
    if _oidc_discovery is None:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url, timeout=10)
        response.raise_for_status()
        _oidc_discovery = response.json()
    return _oidc_discovery


def get_jwks():
    """Fetch and cache the JWKS (JSON Web Key Set) from the provider."""
    global _jwks
    if _jwks is None:
        discovery = get_oidc_discovery()
        jwks_uri = discovery['jwks_uri']
        response = requests.get(jwks_uri, timeout=10)
        response.raise_for_status()
        _jwks = response.json()
    return _jwks


def decode_id_token(id_token, nonce=None):
    """
    Decode and validate the id_token using the provider's JWKS.
    Verifies signature, issuer, audience, expiration, and nonce.
    """
    jwks = get_jwks()
    discovery = get_oidc_discovery()

    # Get the unverified header to find the key ID
    unverified_header = jwt.get_unverified_header(id_token)
    kid = unverified_header.get('kid')

    # Find the matching key in JWKS
    rsa_key = None
    for key in jwks.get('keys', []):
        if key.get('kid') == kid:
            rsa_key = key
            break

    if rsa_key is None:
        # Try refreshing JWKS in case keys were rotated
        global _jwks
        _jwks = None
        jwks = get_jwks()
        for key in jwks.get('keys', []):
            if key.get('kid') == kid:
                rsa_key = key
                break

    if rsa_key is None:
        raise JWTError("Unable to find matching key in JWKS")

    # Decode and validate the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
        audience=OIDC_CONFIG['client_id'],
        issuer=discovery['issuer'],
        options={
            'verify_at_hash': False,
        }
    )

    # Verify nonce if provided
    if nonce and claims.get('nonce') != nonce:
        raise JWTError("Invalid nonce in id_token")

    return claims


def login_required(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['next_url'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


