@app.route('/logout')
def logout():
    """Log out the user by clearing the session and optionally redirecting to provider logout."""
    # Get the id_token for logout hint before clearing session
    tokens = session.get('tokens', {})

    # Clear the session
    session.clear()

    # Try to redirect to the provider's end_session_endpoint if available
    try:
        discovery = get_oidc_discovery()
        end_session_endpoint = discovery.get('end_session_endpoint')
        if end_session_endpoint:
            logout_params = {
                'post_logout_redirect_uri': request.url_root,
                'client_id': OIDC_CONFIG['client_id'],
            }
            if tokens.get('access_token'):
                # Some providers accept id_token_hint
                pass
            logout_url = f"{end_session_endpoint}?{urlencode(logout_params)}"
            return redirect(logout_url)
    except Exception:
        pass  # If discovery fails, just redirect to home

    return redirect(url_for('index'))


